"""
MKT Context Commentary — Genesis chapters 17–19
Run: python3 scripts/zc-context-genesis-17-19.py

Source data used:
- data/interlinear/genesis.json
- data/translation/draft/mediating/genesis.json (MKT text)
- data/commentary/mkt-context/genesis.json (existing ch15:17 entry for style reference)

Key decisions in this range:
- Ch17:v1 ʾĒl Šadday: "God Almighty" — ancient divine epithet, possibly "mountain god"
  or "sufficient one"; LXX=pantokrator; used 6x in patriarchal narratives, 31x in Job
- Ch17:v5 Abram→Abraham: name expanded to embed covenant promise (ʾab hămôn gôyîm)
- Ch17:v8 gēr (resident alien): the irony of Abram as alien in his promised land — not glossed over
- Ch17:v12 eighth-day circumcision: distinctively Israelite (vs. Ishmael's 13 years at puberty, v25)
- Ch18:v2 three men / YHWH: narrative presents them as men throughout; identity reveals gradually
- Ch18:v19 yadaʿ (knew/chose): election vocabulary — "I have known him" = covenant intimacy/choice
- Ch18:v25 "Judge of all the earth": universal divine jurisdiction cited by Abraham in intercession
- Ch19:v5 yādaʿ (know sexually): same verb as Gen 4:1 — the Sodom sin named through this word
- Ch19:v8 Lot's daughter offer: ANE guest-protection absolute; noted without endorsement
- Ch19:v24 double "the LORD" in Hebrew: noted as ANE idiom for emphatic divine action (not allegorized)
- Ch19:v37-38 Moab/Ammon: etiological function; Ruth's Moabite lineage noted as subsequent significance
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    """Merge new_data into existing without overwriting present entries."""
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

GENESIS_CONTEXT = {
  "17": {
    "1": """<p>The divine self-introduction "I am God Almighty (<em>ʾĒl Šadday</em>)" marks Abram's third major theophany and the first use of this divine name. <em>ʾĒl Šadday</em> is used six times in the patriarchal narratives and thirty-one times in Job; the LXX renders it <em>pantokrator</em> (Almighty). Its etymology is debated — possibly "God of the mountains" (from <em>šad</em>, mountain, cf. Akkadian <em>šadū</em>), "God the Sufficient One" (from <em>šādad</em>, to be powerful), or "God who nurses" (from <em>šad</em>, breast, emphasizing sustaining provision). "Walk before me faithfully and be blameless (<em>tāmîm</em>)" — the same word used of Noah in 6:9; it means wholeness/integrity of life, not moral perfection. The covenant-ethics demand accompanies the covenant-promise.</p>""",
    "2": """<p>"I will make my covenant (<em>ʾĕttĕnāh bĕrîtî</em>)" — the verb is "give/set" rather than "initiate"; the covenant was established in ch15; here it is being specified, expanded, and sealed with the circumcision sign. The framing "greatly increase your numbers" (<em>ʾarbeh ʾôtĕkā bimʾōḏ mĕʾōḏ</em> — double-<em>mĕʾōḏ</em> intensifier) repeats the offspring promise at the moment of the covenant's formalization. In ANE suzerain-vassal treaties, the great king's self-introduction ("I am...") followed by his past benefits and future commitments is the standard treaty preamble — Genesis 17 follows this structure closely.</p>""",
    "3": """<p>"Abram fell facedown" (<em>wayyippōl ʾaḇrām ʿal-pānāyw</em>) — the prostration posture (<em>hištaḥăwāh</em>, bowing to the ground) is the standard ANE posture before a superior: a king, a divine being, or a person of greatly higher status. The same posture appears at every major Abrahamic theophany and throughout prophetic accounts of divine encounter (Ezekiel prostrates at each theophanic vision, Ezek 1:28; 3:23; 9:8). The physical act of falling facedown is the somatic response to the overwhelming of normal human standing before the divine presence.</p>""",
    "4": """<p>"You will be the father of many nations (<em>ʾab hămôn gôyîm</em>)" — the covenant declaration anticipates the name change of v5. The phrase <em>hămôn gôyîm</em> (multitude of nations) is embedded in the new name Abraham: <em>ʾaḇrāhām</em> is a phonetic expansion of <em>ʾaḇrām</em> with the sound of <em>hāmôn</em> (multitude) embedded — the name carries the promise in its syllables. The covenant explicitly extends beyond Israel: "many nations" encompasses Ishmael's twelve rulers (v20), the sons of Keturah (25:1-4), and ultimately the Gentile inclusion in the Abrahamic covenant that Paul argues from in Gal 3:8,29.</p>""",
    "5": """<p>Abram → Abraham — name changes in the ANE mark a new covenant identity or social status. The change from <em>ʾaḇrām</em> (exalted father) to <em>ʾaḇrāhām</em> (father of many/a multitude) embeds the covenant promise in the name itself: every time the name is spoken, the promise is reiterated. The same identity-marking function underlies Jacob → Israel (32:28), and Sarai → Sarah (v15). In later rabbinic tradition (and Heb 11:8-12), the name change is treated as a covenant act with lasting significance — after ch17, the narrative never reverts to "Abram."</p>""",
    "6": """<p>"I will make you very fruitful; I will make nations of you, and kings will come from you" — the royal-lineage element of the Abrahamic covenant. Kings descending from Abraham through Sarah (v16: kings from her also) traces the line to David (2 Sam 7:12-16) and Solomon. The "kings from you" fulfillment includes the entire Davidic dynasty and ultimately, in NT reading, Christ the messianic King (Matt 1:1: "son of David, son of Abraham"; Rev 17:14: "King of kings"). The promise of kings from a nomadic patriarch with no biological heir is the kind of audacious promise that the ANE audience would have recognized as extraordinary.</p>""",
    "7": """<p>"I will establish my covenant as an everlasting covenant (<em>bĕrît ʿôlām</em>)" — the same <em>ʿôlām</em> covenant-language as the Noahic covenant (9:16) — permanent, unconditional on the human partner's sustained compliance. "To be your God and the God of your descendants after you" — the covenant formula "I will be your God / you will be my people" appears in full form here for the first time; it recurs throughout the OT as the summary of the covenant relationship (Jer 7:23; 11:4; 30:22; Ezek 36:28; 37:23,27; Zech 8:8; 2 Cor 6:16; Rev 21:3). This formula is the canonical shorthand for the entire covenant relationship.</p>""",
    "8": """<p>"The whole land of Canaan, where you now reside as a foreigner (<em>gēr</em>)" — the narrative irony is pointed: Abram is a <em>gēr</em> (resident alien without land rights) in the very land promised to him as an everlasting possession. The tension between present landlessness and future possession is the constitutive experience of the patriarchal narrative: Abraham buys only a burial plot (ch23) and Jacob returns to Egypt. The <em>gēr</em> status defines the patriarchs' relationship to Canaan until the conquest — possession is covenantal before it is territorial. The same tension defines Israel in Egypt (a nation of <em>gērîm</em>) and, the NT argues, the church as "aliens and strangers" (1 Pet 2:11) awaiting the promised inheritance.</p>""",
    "9": """<p>"As for you (<em>wĕʾattāh</em>), you must keep my covenant" — the human obligation of the covenant is formally introduced. The covenant of ch15 was unilateral (YHWH alone walked through the pieces); ch17 introduces the bilateral sign: YHWH's covenant commitment is responded to by the human covenant marker. The covenant has two movements: divine promise-pledge (vv1-8) and human sign-pledge (vv9-14). The covenant is not earned by the sign, but the sign is not optional — its absence is a covenant violation (v14: "cut off from his people").</p>""",
    "10": """<p>"Every male among you shall be circumcised (<em>yimmôl</em>)" — the circumcision command uses the Niphal of <em>mûl</em> (to circumcise), a technical cultic-legal term. Circumcision was practiced by Egyptians (Herodotus, Histories 2.36-37), some Semitic peoples (Jeremiah 9:25-26 lists the circumcised nations alongside Israel: Egypt, Judah, Edom, Ammon, Moab, Kedar), and Arab tribes — but not by Philistines or Assyrians. Israel's use of circumcision as covenant-identity marker in this ANE context is distinctive for its specific theological rationale (covenant sign) rather than merely hygienic or initiation practice.</p>""",
    "11": """<p>Circumcision as sign (<em>ʾôt</em>) — the same Hebrew word used for the Noahic rainbow (9:12,13,17), the Sabbath sign (Exod 31:13), and the blood on the Passover doorpost (Exod 12:13). Signs in the OT are concrete, visible markers that point to an invisible covenant reality — they do not create the reality but mark and confirm it. Paul's argument in Rom 4:11 — "Abraham received the sign of circumcision as a seal of the righteousness he had by faith while he was still uncircumcised" — exploits the temporal order of ch15 (faith/righteousness, v6) before ch17 (circumcision sign): the sign follows the reality, not the other way around.</p>""",
    "12": """<p>"Every male among you who is eight days old must be circumcised" — the eight-day specification for infant circumcision is distinctively Israelite. Ishmael's circumcision at thirteen (v25) represents a pattern associated with Arabian tribes and the Islamic tradition of circumcision near puberty. The eight-day rule was established for male infants born in the household; adult males circumcised upon joining the household (vv23,27) receive the sign as adults. The eighth day in Levitical law also marks the completion of the dedication period for priests (Lev 8:33-9:1) and the minimum age for sacrificial animals (Lev 22:27) — the eighth day is the threshold of covenantal viability.</p>""",
    "13": """<p>"My covenant in your flesh (<em>bĕrîtî biḇśarĕkem</em>) is to be an everlasting covenant" — circumcision is an embodied covenant: the physical mark on the body represents the covenant claim on the whole person and the covenant people. The flesh becomes the bearer of the covenant sign — the most intimate possible location for a public marker. The prophetic interiorization of circumcision ("circumcise your hearts," Deut 10:16; 30:6; Jer 4:4; 9:26) does not abolish the physical sign but argues that the physical sign must correspond to an inner reality. Paul argues in Col 2:11 that Christ's "circumcision" (his death) produces the interior circumcision of the heart that the physical sign pointed toward.</p>""",
    "14": """<p>"Any uncircumcised male... will be cut off (<em>nikkĕrĕtāh</em>) from his people" — the <em>karet</em> (cutting-off) penalty is a divine judgment form distinct from judicial execution. The OT uses <em>karet</em> for violations of covenant boundary markers: eating leavened bread at Passover (Exod 12:15,19), violating the Sabbath (Exod 31:14), and various cultic transgressions (Lev 17-20 list numerous <em>karet</em> offenses). The <em>karet</em> penalty is exclusion from the covenant community — which in the OT context means exclusion from the divine presence and covenant-protection. The wordplay is pointed: the word for covenant-cutting (<em>kārat bĕrît</em>) and the word for cutting-off as punishment (<em>kārat</em>) share the same root.</p>""",
    "15": """<p>Sarai → Sarah — both names derive from the root <em>śārar</em> (to rule/be a prince); the forms are variant spellings of "princess/noble woman." Unlike Abram/Abraham (where the meaning changes significantly), the name-change for Sarah is subtle — it marks covenant identity rather than semantic expansion. She is now the explicitly designated covenant-mother, not merely Abram's wife. In the Ugaritic texts (<em>šrrt</em>) and Akkadian (<em>šarratu</em>), the cognate means "queen" — the name's royal connotation anticipates the promise of v16 that "kings of peoples will come from her."</p>""",
    "16": """<p>"I will bless her and will surely give you a son by her. I will bless her so that she will be the mother of nations; kings of peoples will come from her" — Sarah receives a direct divine blessing parallel to Abraham's (vv1-8); the covenant-promise is not merely to the patriarch but to the matriarch equally. The royal-lineage specification ("kings of peoples will come from her") narrows the covenant-heir line to Sarah's son specifically, excluding Hagar's line. This specification explains why Ishmael — though blessed — cannot be the covenant heir: the royal-messianic line runs through Sarah.</p>""",
    "17": """<p>Abraham's laughter (<em>wayyiṣḥaq</em>) — the same verb as Isaac's name (<em>yiṣḥāq</em>). The name Isaac embeds three laughs: Abraham's incredulous laugh here (v17), Sarah's disbelieving laugh in 18:12, and the laugh of joy at Isaac's birth (21:6: "God has brought me laughter, and everyone who hears about this will laugh with me"). The name "he laughs" names the child of impossible promise through the human laughter that greeted that promise. The inner monologue — "Will a son be born to a man a hundred years old? Will Sarah bear a child at the age of ninety?" — reflects the physiological reasoning that makes the promise humanly unimaginable.</p>""",
    "18": """<p>"If only Ishmael might live under your blessing (<em>lûlēy yišmāʿēl yiḥyeh lĕpānêkā</em>)!" — Abraham's pastoral intercession for his existing son. The particle <em>lûlēy</em> expresses a wish the speaker does not expect will be granted — Abraham is asking that YHWH's purpose be satisfied through Ishmael rather than through the impossible promise. The request shows that Abraham has bonded with the son he has raised for thirteen years (Ishmael is now 13, v25) and that he finds the covenant's focus on an unborn son difficult to absorb. The request is not rejected but redirected: Ishmael will be blessed (v20), but not through him will the covenant run (v21).</p>""",
    "19": """<p>"Your wife Sarah will bear you a son, and you will call him Isaac (<em>yiṣḥāq</em>)" — Isaac is named by YHWH before birth, as Ishmael was (16:11). Only Ishmael and Isaac among the patriarchs are divinely named before birth — a marker of their special covenant significance (compare Jeremiah named before birth, Jer 1:5; John the Baptist, Lk 1:13; Jesus, Lk 1:31). "I will establish my covenant with him as an everlasting covenant for his descendants" — the contrast with v20 (where Ishmael receives blessing, not covenant) is the exegetical foundation of Paul's argument in Gal 4:21-31: the children of promise vs. the children of flesh are distinguished by covenant-status, not ethnic descent.</p>""",
    "20": """<p>Ishmael's specific blessing — "twelve rulers (<em>šĕnêm ʿāśār nĕśiʾîm</em>)" — enumerated in 25:13-16 as the twelve sons of Ishmael who became the leaders of Arabian tribal confederacies. The twelve-ruler structure mirrors Israel's twelve tribes (twelve sons of Jacob), though through one son rather than through covenant multiplication. "A great nation (<em>gôy gādôl</em>)" — the same designation used for Israel (Deut 4:6,8; 26:5). YHWH grants Ishmael national greatness without the covenant-line — the excluded line is not condemned but given a generous alternative destiny.</p>""",
    "21": """<p>"But my covenant I will establish with Isaac, whom Sarah will bear to you by this time next year (<em>lammôʿēd hazzeh bašānāh hāʾaḥeret</em>)" — the specific timeframe "by this appointed time next year" (<em>lammôʿēd</em>, at the appointed/fixed time) is the same word used in 18:14 and 21:2. The term <em>môʿēd</em> (appointed time/festival) has covenantal weight: it is the word for the "appointed feasts" of YHWH in Lev 23. The covenant heir arrives "at the appointed time" — YHWH's timing is not arbitrary but fixed by covenant commitment.</p>""",
    "22": """<p>"God went up from him" (<em>wayyaʿal ʾĕlōhîm mēʿal ʾaḇrāhām</em>) — the divine withdrawal after theophany is the standard narrative marker for the end of the encounter. The same vertical language appears at the Bethel theophany (28:12-13: YHWH "above" the ladder; the ascending and descending angels), and anticipates the later Ascension language (Acts 1:9-11). In the ANE context, divine appearances were understood as the deity descending to the human level for communication and returning to the divine realm afterward; the directional language is theophanic convention.</p>""",
    "23": """<p>"On that very day (<em>baʿeṣem hayyôm hazzeh</em>) Abraham took his son Ishmael and circumcised them" — the phrase <em>baʿeṣem hayyôm hazzeh</em> (in the bone/substance of this same day) is a rare emphasis-formula that marks epoch-boundary events: the Exodus departure (Exod 12:17,41,51), the entry into the promised land (Josh 5:11), and the Jerusalem siege beginning (Ezek 24:2). Abraham's immediate obedience — on the same day he received the command — is the narrative's commendation of covenant faithfulness without delay. The prompt obedience contrasts with the hesitation of Lot in 19:16.</p>""",
    "24": """<p>Abraham was ninety-nine years old when he was circumcised — an adult male circumcision at that age is a physically costly act. The covenant-sign is not received passively but involves genuine physical sacrifice by the covenant-head. The adult circumcision of Abraham (as opposed to the infant circumcision established for subsequent generations) establishes the covenant at the maximum cost: the founder of the covenant-family receives the sign at the age when it is most demanding, not most convenient.</p>""",
    "25": """<p>Ishmael was thirteen when he was circumcised — his age at the covenant-sign corresponds to the pattern associated with initiation-circumcision in Arabian tribal traditions. The Islamic tradition of circumcision as a mark of male religious identity derives partly from Ishmael's example, though the specific age of thirteen is not universally followed in Islamic practice (the tradition varies from infancy to puberty). The contrast with Isaac's eighth-day circumcision (21:4) is the contrast between the covenant-heir (eighth day, the Israelite sign) and the blessed-but-excluded line (initiation timing, a different cultural pattern).</p>""",
    "26": """<p>Both Abraham and Ishmael circumcised "on that same day" — covenant solidarity; father and son enter the covenant sign together. The household unity of the circumcision event echoes the household-salvation pattern of Noah's ark (all who entered were saved together) and the Passover blood on the household doorpost (the household unit as covenant beneficiary). The covenant-sign is both individual (each person's body) and communal (the household enters together).</p>""",
    "27": """<p>"Every male in Abraham's household, including those born in his household or bought from a foreigner, was circumcised with him" — the covenant sign extends to all males of the household regardless of ethnicity. The slaves purchased from foreigners (<em>ben-nēkār</em>, foreign-born) are circumcised as full members of the covenant household; their ethnic origin is no barrier to covenant inclusion. This expansive covenant community — defined by household membership and circumcision rather than ethnic descent — is the principle Paul will cite (Gal 3:28-29) for the Gentile inclusion in the Abrahamic covenant through faith.</p>"""
  },
  "18": {
    "1": """<p>The theophany "near the great trees of Mamre (<em>ʾēlônê Mamrê</em>)" — the same sacred grove where Abraham had built his fourth Canaanite altar (13:18) and where the theophany of ch18 will plant a permanent covenant marker. "The heat of the day (<em>ḥōm hayyôm</em>)" — the noon hour, the hottest part of the day, when ANE culture rested. Abraham's rushing from rest to greet three strangers at the hottest hour makes his hospitality more notable: he abandons his rest to serve. The Mamre grove becomes the site of both covenant announcement (the Isaac promise) and covenant intercession (the Sodom negotiation) — the place of Abraham's most intense divine encounters.</p>""",
    "2": """<p>"Three men (<em>šĕlōšāh ʾănāšîm</em>) standing nearby" — the narrative presents the visitors as men throughout ch18; only the retrospective revelation that "Abraham remained standing before the LORD" (v22) and the angels' arrival in Sodom (19:1) clarifies the identities. The ambiguity is the narrative's craft: the reader discovers gradually what Abraham may or may not have known. Christian interpreters from Justin Martyr onward have read the three as a Trinitarian appearance; the text itself does not support this reading explicitly. Heb 13:2 cites this episode for its hospitality lesson: "some people have shown hospitality to angels without knowing it." Abraham's bowing to the ground (<em>wayyištaḥû ʾārṣāh</em>) is the standard greeting prostration for honored visitors.</p>""",
    "3": """<p>"If I have found favor (<em>māṣāʾtî ḥēn</em>) in your eyes, my lord, do not pass your servant by" — the vocabulary of patron-client relationship; finding favor (<em>ḥēn</em>) in the eyes of a patron/superior is the standard ANE formula for requesting a benefit. Abraham addresses the visitors as "my lord" (<em>ʾăḏōnāy</em>) — either the plural form of "lord" as honorific (addressed to three visitors) or the divine address (if Abraham recognizes YHWH). The request "do not pass by (<em>ʿal-naʾ taʿăḇōr</em>)" uses the same verb (ʿāḇar, pass over/through) as the Passover (Exod 12:12-13: YHWH "passing through" Egypt to strike; "passing over" Israelite houses). The encounter is structured by the same hospitality-urgency as Lot's invitation in 19:2.</p>""",
    "4": """<p>"Let a little water be brought, and then you may all wash your feet and rest under this tree" — the hospitality sequence of foot-washing, rest, and food is the standard ANE three-stage welcome for travelers. Foot-washing removed the dust of travel and was the host's first practical gift to the guest; it was performed by the host or a servant (cf. Lk 7:44 where Jesus notes that the sinful woman's washing of his feet fulfilled the hospitality the Pharisee neglected). The tree provides shade — the essential comfort in the noon heat. Abraham's hospitality protocol follows the sequence exactly before the divine-promise exchange of vv9-14.</p>""",
    "5": """<p>"Let me get you something to eat, so you can be refreshed (<em>wĕsaʿăḏû libbĕkem</em>)" — literally "sustain your heart"; the idiom for hospitality-restoration. "Now that you have come to your servant (<em>ʿaḇdĕkem</em>)" — Abraham's self-designation as "your servant" is the formal address of a social inferior to a superior, here used as a hospitality formula: "since you have honored your servant by coming to him." The visitors' acceptance — "do as you say" — is the ANE conventional response to a host's invitation; declining would have been a social insult to the host's honor.</p>""",
    "6": """<p>"Three seahs (<em>šĕlōšet sĕʾîm</em>) of the finest flour (<em>sōlet</em>)" — three seahs is approximately 36-40 liters of flour (a seah = about 12-13 liters), enough bread for an extended feast rather than three individuals. The quantity signals hospitality abundance, not merely sufficiency. <em>Sōlet</em> (fine/sifted white flour) is the quality-flour used for special offerings and festivals (Lev 2:1; 6:15; Num 28:9); using it for guest hospitality signals best-quality treatment. Abraham's "quick" (<em>mahēr</em>) — the urgency of hospitality is emphasized throughout the passage: he runs (v2), hurries (v6,7), and urges speed.</p>""",
    "7": """<p>"He ran to the herd and selected a choice, tender calf" — the animal selection for hospitality follows the ANE pattern of slaughtering the best specimen for honored guests. A "choice, tender calf" (<em>ben-bāqār raḵ wĕṭôḇ</em>, literally "son of the herd, tender and good") is the premium animal — fully grown but still young enough to be tender. The parallel to Lk 15:23 (the prodigal's father slaughtering "the fattened calf" upon his son's return) reflects the same ANE hospitality-vocabulary: the best animal for the most honored occasion. "Who hurried to prepare it" — the servant's haste mirrors Abraham's own urgency; the entire household mobilizes for the hospitality event.</p>""",
    "8": """<p>"Curds (<em>ḥemʾāh</em>) and milk and the calf" — the menu of curds, milk, and veal is a substantial feast. The question of whether the milk-and-meat combination violates later kashrut (Exod 23:19: "do not cook a young goat in its mother's milk") is a traditional Jewish hermeneutical discussion; the prohibition was formulated after this event and the narrative presents Abraham's menu as exemplary hospitality, not as a violation. "While they ate, he stood near them under a tree" — the host standing while guests eat is the ANE posture of attentive service, not subservience in a degrading sense; it is the honor-practice of making oneself available to the guests' needs throughout the meal.</p>""",
    "9": """<p>"Where is your wife Sarah?" — the visitors' knowledge of Sarah's name (before being told) is the first signal to the careful reader that these are not ordinary travelers. In the ANE domestic context, a woman would not typically be present at the men's hospitality encounter; Sarah is in the tent — the appropriate location for women during male-guest interactions. The question "where is Sarah?" activates the narrative shift from the hospitality scene to the promise-announcement of v10: the question is not a request for information but a preparation for what follows. "There, in the tent (<em>bāʾōhel</em>)" — the tent as a symbol of the household's transitional/pilgrim status; the covenant-mother is in the place of transitional dwelling when the covenant-promise is renewed.</p>""",
    "10": """<p>"I will surely return to you about this time next year (<em>kāʿēt ḥayyāh</em>)" — the specific timeline makes the promise concrete and verifiable; "at this time, when life comes" (a phrase possibly related to the spring birthing season) or "at this time next year when [Sarah] is alive/well." The same formula is used in 2 Kgs 4:16-17 when Elisha promises the Shunammite woman a son — the verbal parallel between Abraham/Sarah and the Shunammite/Elisha may be a deliberate intertextual echo. Sarah's "listening at the entrance to the tent, which was behind him" — she is within earshot but not in the social space of the men's encounter; her position behind the visitor establishes her as an unseen witness to a promise made about her.</p>""",
    "11": """<p>"The way of women (<em>ʾōraḥ kannāšîm</em>) had ceased for Sarah" — the ANE euphemism for menopause; the "way/custom of women" refers to menstrual cycling, which must cease for fertility to operate. The narrator's parenthetical establishes the biological impossibility of the promise: not merely delayed fertility but post-menopausal impossibility. "Abraham and Sarah were already very old (<em>zĕqēnîm bāʾîm bayyāmîm</em>)" — literally "advanced in days"; the same idiom used for Joshua (Josh 13:1; 23:1,2) and for Eli (1 Sam 2:22). The double establishment of impossibility (very old + post-menopausal) frames Isaac's birth as unambiguously miraculous when it occurs.</p>""",
    "12": """<p>Sarah's laughter and inner monologue — "After I am worn out (<em>belōtî</em>) and my lord (<em>ʾăḏōnî</em>) is old, will I now have this pleasure (<em>ʿednāh</em>)?" The word <em>ʿednāh</em> (pleasure/delight) shares its root with <em>ʿēden</em> (Eden/delight); Sarah's thought is about marital intimacy-pleasure restored in old age — not just pregnancy but the conjugal life she has left behind. 1 Pet 3:6 cites Sarah's use of <em>ʾăḏōnî</em> (my lord) for Abraham as the model of a wife's respectful relationship — the address is the ANE norm for a wife addressing her husband and reflects the honor vocabulary of the household-covenant.</p>""",
    "13": """<p>YHWH's response — "Why did Sarah laugh (<em>lāmmāh ẓāḥăqāh Śārāh</em>)?" — the divine direct address to Abraham about Sarah's inner thought is the theophanic moment that reveals YHWH's access to Sarah's hidden thought. She had "laughed to herself" (<em>batteqereb</em>, within herself) — inwardly, not aloud. YHWH's knowledge of her inner laughter is evidence of his omniscience and simultaneously a gentle exposure: "Will I really have a child, now that I am old?" — the question repeats Sarah's thought back to her in a form that reveals its faithlessness, preparing for the correction of v14.</p>""",
    "14": """<p>"Is anything too hard (<em>hayippālēʾ dāḇār</em>) for the LORD?" — the rhetorical question uses <em>pālāʾ</em> (wonderful/extraordinary/too difficult) — the same root as the messianic title in Isa 9:6 (<em>pele</em>, "Wonderful Counselor") and the divine name "<em>pĕlî</em>" (wonderful) in Judg 13:18. The divine rhetorical question implies its own negative answer: nothing is too extraordinary for YHWH. The same question is echoed in Jer 32:17,27 (YHWH's self-assertion before the Babylonian siege) and in the angel's word to Mary (Lk 1:37: "nothing will be impossible with God," <em>ouk adunatēsei para tō theō pan rhēma</em>). "At the appointed time (<em>lammôʿēd</em>)" — the same covenant-appointment language as 17:21.</p>""",
    "15": """<p>Sarah's denial — "I did not laugh (<em>lōʾ ṣāḥaqtî</em>)" — the first lie in the Sarah-narrative; she was afraid (<em>wayyirāʾ</em>). The fear-response to divine exposure is characteristic throughout Genesis: exposure of hidden states produces fear (Adam's hiding, 3:10; Hagar's "I have seen the One who sees me," 16:13). YHWH's response — "Yes, you did laugh (<em>lōʾ kî ṣāḥaqt</em>)" — is gently firm; the denial is corrected without condemnation, and the encounter does not end in punishment. The correction is itself a grace: Sarah is confronted with her doubt in a context where the promise-giver then departs without withdrawing the promise.</p>""",
    "16": """<p>"Abraham walked along with them to see them on their way (<em>lĕšalĕḥām</em>)" — the farewell-accompaniment (<em>lĕwāyāh</em>, escort/walking with) was the final hospitality obligation in ANE culture; the host accompanied departing guests to the edge of the hosting territory. The same farewell-accompaniment is practiced by Lot (19:2 — though he does not walk them out, they will not go to the square alone) and by Abraham's servant (24:59: Rebekah's household sends her away with their blessing). The narrative's transition from hospitality at Mamre to the walk toward Sodom marks the shift from the first act (promise of Isaac) to the second act (judgment of Sodom).</p>""",
    "17": """<p>"Shall I hide from Abraham what I am about to do?" — YHWH's interior deliberation, narrated for the reader. The divine "speaking to himself" is a narrative device for revealing divine motivation; in the ANE context it is the king's council deliberation made audible. The question is rhetorical — YHWH proceeds to tell Abraham — but the articulation of the question establishes the principle: covenant partners are given foreknowledge of divine judgment in which they have a stake. This pattern recurs when YHWH tells Amos "Surely the Sovereign LORD does nothing without revealing his plan to his servants the prophets" (Amos 3:7).</p>""",
    "18": """<p>"Abraham will surely become a great and powerful nation, and all nations on earth will be blessed through him (<em>wĕniḇrĕḵû ḇô kōl gôyê hāʾāreṣ</em>)" — the repetition of the 12:3 covenant-promise at this hinge moment (between the Isaac-promise and the Sodom-judgment) is not incidental. It establishes Abraham as the covenant-mediator whose intercession for Sodom in vv23-32 flows directly from his covenant-status: as the source of blessing for "all nations," Abraham has the standing and the motivation to intercede for nations facing judgment. Paul quotes this verse (Gal 3:8) as the foundational statement of justification by faith extended to Gentiles.</p>""",
    "19": """<p>"For I have chosen him (<em>yĕdaʿtîw</em>, literally 'I have known him')" — <em>yādaʿ</em> (to know) in this context means covenant-election/intimacy, not merely cognitive knowledge. The same election vocabulary appears in Jer 1:5 ("before I formed you I knew you"), Amos 3:2 ("only you have I known among all the families of the earth"), and Rom 8:29 ("those he foreknew"). "So that he will direct his children and his household after him to keep the way of the LORD (<em>derek YHWH</em>) by doing what is right (<em>ṣĕdāqāh</em>) and just (<em>mišpāṭ</em>)" — the covenant's purpose is multigenerational: Abraham is elected not for his own benefit alone but to create a household-tradition of covenant faithfulness across generations.</p>""",
    "20": """<p>"The outcry (<em>ẓaʿăqāh</em>) against Sodom and Gomorrah is so great and their sin so grievous" — the same word used for Israel's cry in Egyptian slavery (Exod 2:23; 3:7: "I have heard the cry of my people"). The outcry model of divine response is consistent: oppressed parties cry out (<em>ẓāʿaq</em>), YHWH hears, YHWH responds with judgment on the oppressor. In Sodom's case, the outcry against the city reaches YHWH — the victims of Sodom's violence have cried out, and YHWH's investigation-and-judgment is the forensic response. Ezek 16:49-50 specifies what Sodom's sin encompassed beyond the specific violence of ch19: "arrogance, overfed and unconcerned; they did not help the poor and needy."</p>""",
    "21": """<p>"I will go down and see (<em>ʾērĕḏāh-nāʾ wĕʾerʾeh</em>)" — the anthropomorphic language for divine judicial investigation, paralleling 11:5 (YHWH "comes down" to see Babel). The divine descent-to-see is not a limitation on divine omniscience but a forensic convention — the act of "going down to see" establishes the legal thoroughness of the investigation before judgment falls. The phrase "if not, I will know (<em>ʾēḏāʿāh</em>)" — a conditional that leaves open the possibility the outcry was exaggerated — further establishes the judicial fairness of what follows. YHWH investigates before executing; he does not execute blindly.</p>""",
    "22": """<p>"Abraham remained standing before the LORD (<em>wayyaʿămōḏ ʾaḇrāhām lĕpānê YHWH</em>)" — the audacious posture of the intercessor. Standing before YHWH is the servant's posture (the angles "stand" before YHWH in Job 1:6; 2:1; Lk 1:19: "I am Gabriel, who stands in the presence of God"). The intercessor stands where the servant stands — in the divine presence, on behalf of others. Ezek 22:30 expresses the absence of such an intercessor as the tragedy of Jerusalem's fall: "I looked for a man among them who would... stand before me in the gap on behalf of the land... but I found none." Abraham's standing before YHWH for Sodom is the model of covenantal intercession.</p>""",
    "23": """<p>"Will you sweep away the righteous with the wicked (<em>tispeh ṣaddîq ʿim-rāšāʿ</em>)?" — Abraham's intercession begins not with an appeal to divine mercy but to divine justice (<em>ṣĕdāqāh</em>). The argument is a legal one: would a righteous Judge punish the innocent alongside the guilty? The same principle governs OT law (Deut 24:16: "parents are not to be put to death for their children, nor children put to death for their parents; each will die for their own sin") and informs Paul's "justification" arguments (the righteous judge does not condemn the righteous, Rom 8:33-34). Abraham is holding YHWH to his own stated character as the just Judge of all the earth.</p>""",
    "24": """<p>"What if there are fifty righteous people in the city?" — the opening number of Abraham's intercession. The choice of fifty as the starting figure may reflect an intuitive community-size: fifty represents a substantial group, the minimum for a viable covenant-community (fifty is the head-count for Levitical service in Num 4:23,30,35). The "righteous" (<em>ṣaddîqîm</em>) in the city are those whose presence would constitute a warrant for the city's preservation; the righteous remnant preserving the community is a persistent OT principle (Isa 1:9: "unless the LORD Almighty had left us some survivors, we would have become like Sodom"; Rom 9:29 quotes this).</p>""",
    "25": """<p>"Will not the Judge of all the earth (<em>šōpēṭ kol-hāʾāreṣ</em>) do right (<em>mišpāṭ</em>)?" — the title "Judge of all the earth" is Abraham's appeal to YHWH's universal jurisdiction and character. The title names YHWH as the supreme tribunal with authority over all nations — not merely over Israel (which does not yet exist). The appeal is to the consistency of divine character: the God who is just in his covenant cannot be unjust in his judgment. This universal divine sovereignty is the basis for the NT claim that God is the impartial judge (Rom 2:11; Acts 17:31: "he has set a day when he will judge the world with justice by the man he has appointed").</p>""",
    "26": """<p>YHWH's unconditional answer — "If I find fifty righteous people in the city of Sodom, I will spare the whole place for their sake (<em>bāʿăḇûrām</em>)" — the community benefits from the presence of the righteous within it. The principle that a city is spared for the sake of a righteous minority is the inverse of the principle that a city's wickedness can bring judgment on all; both directions of communal representation are in play in the ANE covenantal worldview. The Jeremiad letter (Jer 29:7: "seek the peace and prosperity of the city to which I have carried you... pray to the LORD for it") reflects the same principle for Israelite exiles in Babylon.</p>""",
    "27": """<p>"Now that I have been so bold (<em>hôʾaltî lĕḏabbēr</em>) as to speak to the Lord, though I am nothing but dust and ashes (<em>ʿāpār wāʾēper</em>)" — the self-description "dust and ashes" is the classic ANE expression of human frailty before the divine (<em>ʿāpār</em> = dust of the ground, 2:7; 3:19; <em>ʾēper</em> = ash). Job uses the same phrase in Job 30:19 and 42:6. Abraham's rhetorical self-abasement is the standard form of patron-client negotiation: acknowledging one's inferior status before pressing the request further. The "bold" (<em>hôʾaltî</em>) — literally "I have shown willingness/dared" — acknowledges that the intercession exceeds the normal protocol of the servant's standing before the master.</p>""",
    "28": """<p>"What if the number of the righteous is five less than fifty?" — the first reduction in the intercession series. The step-by-step reduction (50, 45, 40, 30, 20, 10) is not commercial bargaining in a disrespectful sense but a juridical-exploration of the outer limits of divine mercy. Each reduction discovers the same answer: YHWH will spare for fewer. The progression demonstrates that YHWH's mercy is broader than even Abraham's intercession presumes — he did not need to press; YHWH would have spared for forty without being asked. The theological point is not that intercession "changes YHWH's mind" but that intercession articulates what YHWH already intends toward mercy.</p>""",
    "29": """<p>Abraham presses to forty — "For the sake of forty, I will not do it" — the formula varies slightly: for fifty and forty-five, YHWH speaks of sparing "the whole place"; for forty, thirty, twenty, and ten, the formula is "I will not do it." The consistency of YHWH's affirmative response across the reduction series establishes his willingness to spare without limit, pending the righteous actually being present. The narrative's tension is not whether YHWH will agree to spare but whether there are enough righteous to meet even the minimum threshold — a threshold the narrative (in ch19) reveals was not met.</p>""",
    "30": """<p>"May the Lord not be angry (<em>ʾal-yiḥar lāʾdōnāy</em>)" — literally "let it not be hot to the Lord"; the idiom for divine wrath (<em>ḥārāh</em>, to burn/be hot with anger) is the standard ANE metaphor for intense emotion. Abraham's repeated fear that YHWH will be angered by his persistence is part of the patron-client frame: pushing the great king too hard risks royal displeasure. Abraham's willingness to press despite this fear — five more times — is the narrative's portrait of intercessory courage: the love for potential righteous people in Sodom overrides the fear of divine displeasure.</p>""",
    "31": """<p>"What if only twenty can be found there?" — the descent from thirty to twenty is a large step, signaling Abraham's growing awareness that the city may not have many righteous people. "For the sake of twenty, I will not destroy it" — the consistent divine response continues. The pattern of YHWH's unconditional willingness to spare is not modified by Abraham's increasing audacity; the terms remain stable even as the number decreases. This stability of mercy is the theological point: YHWH's willingness to spare is not worn down by negotiation but remains consistently generous.</p>""",
    "32": """<p>"What if only ten can be found there?" — Abraham's stopping point; why he stops at ten is not explained. Later Jewish tradition established ten (<em>minyan</em>) as the minimum viable community for public worship — perhaps Abraham's stopping point reflects an intuition about the minimum covenant-community size. The narrative leaves the question open: did Abraham believe ten was surely enough? Did he not dare ask for fewer? Whatever the reason, the threshold of ten is not met in Sodom — the only righteous person present is Lot, and his righteousness is ambiguous. The intercession that was successful in principle (YHWH agreed) failed in fact (not even ten righteous could be found).</p>""",
    "33": """<p>"When the LORD had finished speaking with Abraham, he left, and Abraham returned home" — the quiet ending of the intercession. No dramatic conclusion; Abraham returns to his household at Mamre. The juxtaposition of the return to normal life with the impending catastrophe at Sodom creates narrative tension: Abraham knows what is coming, but the morning brings no visible sign yet. The covenant partner who has interceded has done what he could; the rest is with YHWH. The narrative then shifts immediately to Sodom (19:1) — a story Abraham will watch from afar at 19:27-28.</p>"""
  },
  "19": {
    "1": """<p>"Lot was sitting in the gateway of the city (<em>yōšēḇ bĕšaʿar-Sĕdōm</em>)" — the city gate was the civic center of ANE cities: judicial proceedings (Deut 21:19; Ruth 4:1-11), commercial transactions (2 Kgs 7:1), and civic administration (Prov 31:23; Job 29:7-10) all took place at the gate. Lot's position in the gateway in 19:1 marks his full civic integration into Sodom — contrasted with his earlier progressions: "near Sodom" (13:12), "among the cities of the plain" (13:12), "in Sodom" (14:12), and now "in the gateway." He is a civic leader, not merely a resident; 2 Pet 2:7-8 calls him "righteous Lot" who was "distressed by the depraved conduct of the lawless" — a righteous man at the center of an unrighteous city.</p>""",
    "2": """<p>Lot's urgent invitation — "please turn aside to your servant's house" — mirrors Abraham's hospitality of ch18, using the same vocabulary of "servant," foot-washing, and overnight stay. But where Abraham pressed from genuine hospitality abundance, Lot's urgency has a protective edge: he "insisted strongly (<em>wayyiṣpôr bām mĕʾōḏ</em>)" because he knew what awaited unprotected strangers in Sodom's city square after dark. The visitors' initial refusal — "we will spend the night in the square" — tests Lot's commitment; his persistence is the act that saves the visitors from the mob.</p>""",
    "3": """<p>"Baking bread without yeast (<em>maṣṣôt</em>)" — unleavened bread, the same term for the Passover bread (Exod 12:8,17-20,39). The narrative echo may be intentional: Lot's "Passover-like" meal on the night before the destruction parallels Israel's Passover meal on the night before the Exodus. Both narratives involve a rescue through divine action, a night of danger and judgment, and a commanded departure at dawn. The rapid preparation of unleavened bread (no waiting for yeast to rise) is the bread of urgency — consistent with the night's narrative tempo.</p>""",
    "4": """<p>"All the men from every part of the city of Sodom — both young and old — surrounded the house" — the comprehensive participation in the demand is the narrative's most damning detail. Not a criminal fringe but "all the men" (<em>kol-hāʿam miqqāṣeh</em>, all the people from every end) of the city; not youthful indiscretion but "both young and old" (<em>minnāʿar wĕʿad-zāqēn</em>), excluding the "ignorance of youth" or "decay of age" explanations. The comprehensiveness establishes that the corruption of Sodom is total — which is why the intercession of ch18 ultimately finds no adequate righteous remnant.</p>""",
    "5": """<p>The demand — "bring them out to us so that we can have sex with them (<em>wĕnēḏĕʿāh ʾōtām</em>)" — the verb <em>yādaʿ</em> (to know) in a sexual context, the same used in 4:1 (Adam "knew" Eve) and 24:16 (Rebekah "not known" by a man). The sexual violence intended against the visitors is the act that gives the name "sodomy" to its primary historical association. The broader sin-picture of Sodom in Ezek 16:49-50 ("arrogance, overfed and unconcerned; they did not help the poor and needy, and they did detestable things before me") contextualizes ch19's specific scene within a pattern of comprehensive covenant-violation: the sexual violence is the culmination, not the totality, of Sodom's sin.</p>""",
    "6": """<p>"Lot went outside to meet them and shut the door behind him" — the physical act of interposing himself between the visitors and the mob is the cost of the ANE hospitality-obligation. A host who took a guest "under his roof" (<em>taḥat ẓēl qōrātî</em>, v8: under the shelter of my roof-beam) was honor-bound to protect that guest at personal cost. Lot's shutting of the door (protecting the visitors inside) while he goes out alone to face the mob is the maximum personal risk the hospitality obligation required. His willingness to face the mob alone is the act that 2 Pet 2:8 credits to his "righteous soul tormented day after day by lawless deeds."</p>""",
    "7": """<p>"Do not do this wicked thing (<em>rāʿāh</em>)" — the same word used by the narrator in 13:13 for Sodom's wickedness. Lot's moral objection to the mob's demand uses the narrator's own evaluative vocabulary — he sees the evil correctly, even if his proposed solution (v8) is itself deeply problematic. The moral clarity of Lot's objection ("this is wicked") stands against the total moral numbness of the mob. The contrast establishes Lot's "righteous" character (2 Pet 2:8) within Sodom's context — he is relatively righteous compared to the city, not absolutely righteous by covenant standards.</p>""",
    "8": """<p>Lot's offer of his daughters — the most difficult passage in Genesis 19. The ANE honor-context: a guest "under the roof" was under the absolute protection of the host; the host's honor was entirely bound to the guest's safety. Lot's offer of his daughters in place of the guests reflects this extreme priority: protecting the guests from dishonor by offering the host's own family instead. The text does not commend this action — the daughters are also under Lot's protection — but the narrative presents it as the moment of maximum desperation within the host-honor framework. The lot of Lot's daughters (violence offered by their own father to protect strangers) is the tragic dimension of living within a city whose violence has normalized the impossible choice.</p>""",
    "9": """<p>"This fellow came here as a foreigner (<em>gēr bāʾ</em>)" — the mob weaponizes Lot's outsider status against his moral objection. He is a <em>gēr</em> (resident alien) in Sodom — accepted but not fully belonging, without full civic standing to "play the judge (<em>šāpōṭ yišpôṭ</em>)" over the city. The irony is double: Lot is a <em>gēr</em> in Sodom (where he has no land rights despite civic presence) just as Abraham is a <em>gēr</em> in Canaan (17:8). The mob's "who gave you authority to judge us?" echoes the Israelite worker's challenge to Moses (Exod 2:14: "who made you ruler and judge over us?") — the pattern of rejecting the covenant-person's moral authority.</p>""",
    "10": """<p>"But the men inside reached out and pulled Lot back into the house and shut the door" — the angelic intervention is the turning point of the narrative. The angels act here with physical force: reaching out, pulling, shutting — not supernatural manifestation but direct physical action. Their protection of Lot reverses his protective gesture of v6: he went out to protect them; they pull him in to protect him. The narrative dynamic models the pattern of divine rescue: the covenant-person risks to protect the divine visitor; the divine visitor ultimately rescues the covenant-person.</p>""",
    "11": """<p>"They struck the men... with blindness (<em>sanewerîm</em>)" — the word <em>sanewerîm</em> is a rare term used only here and in 2 Kgs 6:18 (the Aramean army struck blind at Elisha's request at Dothan). Its etymology is uncertain — possibly related to a Mesopotamian word for sudden blindness or disorientation. "So that they could not find the door" — the mob, though blinded, does not disperse but continues seeking the door; their persistence in blindness (literally wearing themselves out seeking an entrance they cannot find) is the narrative's most disturbing detail: the compulsive violence continues even when it cannot succeed.</p>""",
    "12": """<p>"Do you have anyone else here — sons-in-law, sons or daughters, or anyone else in the city who belongs to you?" — the angels' rescue mandate is comprehensive: they are sent to save all who "belong to" Lot (covenant household) before destruction. The question reveals the rescue's scope: not just Lot individually but his entire household network. The "sons-in-law, sons or daughters" indicates Lot has daughters beyond the two at home (the "daughters pledged to marry," v14, are additional — the two daughters who escape are described as "who are here" suggesting they are the unmarried ones still in the household).</p>""",
    "13": """<p>"We are going to destroy this place" — the angels' self-disclosure as agents of divine judgment. "The outcry to the LORD against its people is so great that he has sent us to destroy it (<em>šālaḥ YHWH ʾōtānû lĕšaḥătāh</em>)" — the divine-mission language echoes prophetic commission vocabulary; the angels are sent agents executing a predetermined judgment. The disclosure to Lot of what is coming — before it happens — follows the same pattern as YHWH's disclosure to Abraham in 18:17: covenant partners are given foreknowledge of divine action that affects them.</p>""",
    "14": """<p>"His sons-in-law thought he was joking (<em>wayhî kĕmĕṣaḥēq bĕʿênê ḥătānāyw</em>)" — the verb <em>ṣāḥaq</em> (to laugh/play/jest) is the same root as Isaac's name (<em>yiṣḥāq</em>). The ironic intersection: in the Abraham narrative, the laughter-root produces the child of covenant promise; in the Lot narrative, the same root produces the comedy of fatal disbelief — those who laughed off the warning perished. The sons-in-law's treatment of the warning as "joking" is the practical effect of living in Sodom's moral atmosphere: a city that mocks judgment cannot hear the warning of judgment seriously.</p>""",
    "15": """<p>"With the coming of dawn, the angels urged (<em>wayyāʾîṣû</em>) Lot" — the urgency of the escape coincides with the dawn; the destruction is coming with the daylight (v23-24). The dawn urgency echoes the Passover departure at night, completed before morning (Exod 12:22: "none of you shall go out the door until morning"). "Or you will be swept away (<em>tissāpeh</em>) when the city is punished (<em>baʿăwôn hāʿîr</em>)" — the same word <em>sāpāh</em> (sweep away) used by Abraham in his intercession (18:23: "will you sweep away the righteous with the wicked?"). The angels are fulfilling the judgment that Abraham's intercession tried to avert.</p>""",
    "16": """<p>"When he hesitated (<em>wayyitmahĕhāh</em>)" — Lot's hesitation at the moment of rescue is the narrative's most piercing detail. The verb <em>māhah</em> (to delay/linger) appears only here and in Judg 3:26 (context of escape) and Gen 43:10 (if we had not delayed). Even facing imminent destruction, Lot cannot bring himself to leave the city he has made his home. "The men grasped his hand and the hands of his wife and of his two daughters and led them safely out of the city, for the LORD was merciful (<em>bĕḥemlat YHWH ʿālāyw</em>) to them" — divine mercy operates through physical compulsion: the covenant-person who cannot rescue himself is physically removed by divine agents. The mercy is the reason for the rescue; the hesitation is the reason the rescue required force.</p>""",
    "17": """<p>"Flee for your lives! Don't look back (<em>ʾal-tabbiṭ ʾaḥărêkā</em>)!" — the prohibition against looking back will be violated by Lot's wife in v26. The prohibition has been interpreted as: a practical command (looking back slows escape); a covenant-boundary instruction (the condemned territory must be left completely); or a symbolic command (the past must not be clung to in the moment of rescue). Jesus' citation — "Remember Lot's wife" (Lk 17:32) — uses it as a warning against turning back from the kingdom of God when the moment of decision comes. "Don't stop anywhere in the plain" — the entire Jordan plain is under judgment; partial evacuation is not safe.</p>""",
    "18": """<p>"But Lot said to them, 'No, my lords, please (<em>ʾal-nāʾ ʾăḏōnāy</em>)!'" — Lot addresses the angels with the same <em>ʾăḏōnāy</em> (my lords/Lord) used by Abraham in 18:3. The negotiation Lot initiates — asking for an alternative escape destination — is remarkable: mid-rescue, he is negotiating terms. The freedom to negotiate with the divine messenger even in a moment of extreme urgency reflects the ANE covenant-relationship between YHWH and his covenant partners: they are not merely commanded but engaged. The angel's willingness to grant the alternative (v21) confirms this.</p>""",
    "19": """<p>"I can't flee to the mountains; this disaster will overtake me, and I'll die" — Lot's practical objection to the commanded mountain-escape reflects his assessment of his own capacity: he cannot run far enough or fast enough to reach the mountains before the destruction overtakes him. The mountains (probably Edom/Moab's highland to the southeast) would require a longer journey. Whether the assessment is accurate or whether it reflects Lot's attachment to the settled-city life — he wants to go to a town (v20), not to the wilderness — the narrative presents it without critique. YHWH grants the alternative, suggesting the objection was valid.</p>""",
    "20": """<p>"Here is a town near enough to run to, and it is small — it is very small (<em>miṣʿār hîʾ</em>), isn't it?" — the smallness of Zoar is doubly emphasized (small... very small), and the name Zoar (<em>ṣōʿar</em>) means "insignificant/small" in Hebrew. The place-name etymology preserves the story: Zoar is named for what Lot said about it in his moment of rescue-negotiation. The preservation of the city's name in Hebrew meaning captures the mercy granted: a small city was spared for a small reason. "Then my life will be spared (<em>tĕḥî napšî</em>)" — literally "my <em>nepeš</em> will live"; the same word used in the Psalms for the soul's survival and deliverance (Ps 33:19; 116:8).</p>""",
    "21": """<p>"Very well, I will grant this request too (<em>šāʾtî ʾet-pānêkā gam liḏḇār hazzeh</em>)" — literally "I have lifted your face" — the ANE idiom for granting a petition and showing favor. The "too" (<em>gam</em>) acknowledges that Lot has already received the major grace of rescue; the alternative destination is an additional concession. "I will not overthrow the town you speak of" — Zoar is explicitly included in the judgment zone (it is one of the five cities, 14:2) but is spared for Lot's sake. The rescue of a condemned city for the sake of one covenant-person is the most extended expression of the ch18 principle: the righteous save the community.</p>""",
    "22": """<p>"I cannot do anything until you reach it (<em>kî lōʾ ʾûkal laʿăśôt dāḇār ʿad-bōʾăkā šāmmāh</em>)" — the divine restraint awaiting Lot's safety is one of the most remarkable statements in Genesis: the execution of judgment is held back by the presence of the righteous. The same principle governs 2 Pet 3:9 (the Lord "is patient, not wanting anyone to perish") and the eschatological withholding of judgment in Revelation. "That is why the town was called Zoar (<em>ṣōʿar</em>)" — the name-etymology formalizes the narrative memory in the place-name: the insignificant small city is named for the moment when significance was granted to the insignificant for the sake of one hesitating man.</p>""",
    "23": """<p>"By the time Lot reached Zoar, the sun had risen over the land" — the timing note establishes the daylight context for the destruction: not a secret act in darkness but a judicial act in full daylight. The sun rising over the land (<em>haššemeš yāṣāʾ ʿal-hāʾāreṣ</em>) marks the transition from the night of rescue to the day of judgment. The same temporal movement — night of salvation / day of judgment — structures the Passover: the destroying angel passes over in the night; Israel departs in the morning; Pharaoh's army is destroyed at the Sea. The Sodom narrative may deliberately anticipate the Exodus pattern.</p>""",
    "24": """<p>"The LORD rained down burning sulfur (<em>gāprît wāʾēš</em>) on Sodom and Gomorrah — from the LORD out of the heavens (<em>mēʾēt YHWH min-haššāmāyim</em>)" — the double mention of YHWH ("the LORD rained... from the LORD out of the heavens") is a Hebrew construction emphasizing the divine source. Ancient interpreters (Justin Martyr, Tertullian) read two divine persons; modern scholarship reads an ANE idiom for emphatic divine agency: the judgment is entirely YHWH's, mediated through natural forces (volcanic sulfur-fire, geological upheaval, or divine incendiary action). Burning sulfur and fire are the judgment materials of prophetic imagery throughout the OT (Isa 34:9; Ezek 38:22; Ps 11:6) and NT (Rev 19:20; 20:10; 21:8).</p>""",
    "25": """<p>"He overthrew those cities and the entire plain (<em>kol-hakkikār</em>), destroying all those living in the cities — and also the vegetation in the land (<em>ṣĕmaḥ hāʾăḏāmāh</em>)" — the ecological totality of the destruction. The once "well-watered" Jordan plain "like the garden of the LORD, like the land of Egypt" (13:10) becomes ash and desolation. The vegetation (<em>ṣĕmaḥ</em>) destruction is significant: the land's fertility — which had made the plain attractive to Lot — is annihilated. The city that consumed rather than produced righteousness loses the ground-fertility that sustained it. Deut 29:23 will use the Sodom-Gomorrah desolation as the paradigm of covenant-curse: a land of "burning sulfur and salt — nothing planted, nothing sprouting."</p>""",
    "26": """<p>"But Lot's wife looked back (<em>wattabbēṭ ʾištô mēʾaḥărāyw</em>), and she became a pillar of salt (<em>nĕṣîḇ melaḥ</em>)" — salt-formations in the Dead Sea region (visible still today as pillar-shaped salt columns) provided the geographic memory for this narrative. The violation of the "don't look back" command (v17) results in the destruction she was fleeing claiming her — she is turned into the landscape of the judgment zone she could not leave behind. Jesus' citation — "remember Lot's wife" (Lk 17:32) — uses her fate as a warning about the cost of turning back when God commands forward movement: to look back is to belong to what is being destroyed.</p>""",
    "27": """<p>"Abraham got up and returned to the place where he had stood before the LORD (<em>ʿāmad lĕpānê YHWH</em>)" — the same "standing before the LORD" of Abraham's intercession in 18:22. Abraham returns to the site of intercession to observe what became of the city he pleaded for. "The place where he had stood" marks the intercessor's location as a covenant-memory site — where the negotiation with YHWH happened. The morning return is the covenant partner's reckoning with the outcome of his intercession: the prayer was offered; the judgment proceeded; the intercessor witnesses both.</p>""",
    "28": """<p>"He saw dense smoke rising from the land, like smoke from a furnace (<em>kĕqîṭōr hakkibbšān</em>)" — the furnace-smoke simile uses <em>kibbšān</em>, the same word for the Sinai theophany's smoke: "Mount Sinai was covered in smoke, because the LORD descended on it in fire. The smoke billowed up from it like smoke from a furnace (<em>kĕqîṭōr hakkibbšān</em>)" (Exod 19:18). The same image for Sodom's destruction and Sinai's theophany creates an ominous intertextual echo: the divine presence in fire and smoke is simultaneously the presence of covenant and the presence of judgment. Abraham witnesses what his intercession could not prevent.</p>""",
    "29": """<p>"God remembered Abraham (<em>wayyizkōr ʾĕlōhîm ʾet-ʾaḇrāhām</em>)" — the covenant-memory formula (as in 8:1: "God remembered Noah"). Lot's rescue is explicitly motivated by the Abrahamic covenant: "he brought Lot out of the catastrophe... when God destroyed the cities." Lot is saved not for his own merit alone but because YHWH's covenant with Abraham extends protection to Abraham's kin — the covenant's reach includes the covenant-partner's household network. The formula "God remembered" in Genesis always marks a pivot from crisis to rescue driven by covenant-loyalty, not human initiative (cf. 30:22: "God remembered Rachel"; Exod 2:24: "God remembered his covenant with Abraham, Isaac, and Jacob").</p>""",
    "30": """<p>"Lot and his two daughters left Zoar and settled in the mountains" — the circuit of Lot's journey: he went from Canaan (covenant land) to the Jordan plain (chosen by sight, 13:10-11), to near Sodom (13:12), to in Sodom (14:12), to the gateway of Sodom (19:1), to Zoar (rescued but still settled), to a mountain cave (isolated, stationary). Each move is downward in covenant terms: from the pilgrim-tent to the city-gate to the cave. The cave-dwelling (<em>yayyēšeḇ bammĕʿārāh</em>) marks the end of Lot's narrative arc — the contrast with Abraham's tent-dwelling (hospitality, mobility, covenant journey) is complete.</p>""",
    "31": """<p>"There is no man around here to give us children — as is the custom all over the earth (<em>kĕdereḵ kol-hāʾāreṣ</em>)" — the daughters' reasoning reflects a perceived catastrophe: they believe the entire world has been destroyed. Isolated in a mountain cave, having witnessed the destruction of the Jordan plain's cities, with no male relatives surviving (the sons-in-law had refused to flee), the daughters conclude that human civilization has ended. Their reasoning is not presented as correct but as the perception that drives the action. The phrase "as is the custom all over the earth" implies they believe normal human reproduction must continue — the obligation of survival-reproduction felt as universal.</p>""",
    "32": """<p>"Let's get our father to drink wine and then sleep with him and preserve our family line (<em>nĕḥayyeh zera</em>, keep alive seed/descendants) through our father" — the plan is presented in terms of the daughters' survival-reasoning, not as a moral endorsement. The same vocabulary of "keeping alive seed" (<em>zera</em>) is used in the Lot-narrative's own preceding context: the rescue from Sodom was to preserve the family (<em>leḥayyōt napeš</em>, 19:19). The daughters' reasoning extends this survival imperative to its logical limit — the family line must continue even by transgressing the incest prohibition. The text presents the plan without authorial comment; the reader is left to supply the moral evaluation.</p>""",
    "33": """<p>"He was not aware of it when she lay down or when she got up" — the repeated formula in vv33 and 35 insists on Lot's complete unawareness; his drunkenness is not complicity but the precondition the daughters exploit. The narrative detail protects Lot from intentional incest (which would have been the greater moral violation in ANE law) while not sparing him the consequences: the actions produce children and ultimately nations. The wine-induced unconsciousness and the formulaic repetition of unawareness serve the narrative's interest in explaining the Moabite and Ammonite origins without condemning Lot as a knowing participant.</p>""",
    "34": """<p>The older daughter's plan for the younger follows the same pattern as v32-33 — the repetition is deliberate: the narrative gives equal weight to both events, establishing the symmetry of the two national origins. The older-then-younger sequence mirrors the reversal pattern in Genesis (Esau/Jacob, Manasseh/Ephraim) where the expected first-born priority is overturned; here the older daughter acts first and bears Moab, the older nation-neighbor to Israel.</p>""",
    "35": """<p>"Again he was not aware of it" — the formula repeated from v33; the narrative insists on the parallelism. The structural regularity of the two events (same night-wine-sleep pattern, same unawareness, same outcome) is the narrative's way of treating the two national origins with equal dignity and equal qualification: neither Moab nor Ammon has a more honorable or less honorable origin than the other. Both nations are born from the same crisis situation of perceived total isolation.</p>""",
    "36": """<p>"So both of Lot's daughters became pregnant by their father" — the narrative concludes the account with the bare statement of outcome. The pregnancy is the goal the daughters had intended; the bare statement of achievement is the narrative's minimal comment. The moral evaluation is left entirely to the reader — the text neither condemns nor approves, but the placement of this episode after the rescue of a "righteous" man who hesitated to leave Sodom and whose wife turned to salt creates the portrait of covenant damage: even the righteous person drawn too deeply into a condemned culture emerges impaired.</p>""",
    "37": """<p>"The older daughter had a son, and she named him Moab (<em>Mōʾāḇ</em>)" — the name Moab may be a wordplay on <em>mēʾāḇ</em> (from father) — explicitly noting the origin of the Moabite nation. The Moabites of the OT are Israel's persistent neighbors-and-enemies to the east of the Jordan: Balak of Moab hires Balaam against Israel (Num 22-24); David subdues Moab (2 Sam 8:2); Mesha of Moab rebels against Israel (2 Kgs 3; the Mesha Stele). But Ruth the Moabitess is the great-grandmother of David (Ruth 4:13-22) — making a Moabitess (descended from Lot's incestuous union) an ancestor of the covenant-king and ultimately of Christ (Matt 1:5). The narrative's irony is complete: the excluded-and-disgraced line contributes to the messianic lineage.</p>""",
    "38": """<p>"The younger daughter also had a son, and she named him Ben-Ammi (<em>ben-ʿammî</em>)" — "son of my people/kinsman" — he is the father of the Ammonites. The Ammonites occupy the territory east of the Jordan north of Moab; their capital Rabbah (modern Amman, Jordan) preserves the name. The Ammonites are among Israel's persistent adversaries (1 Sam 11; 2 Sam 10-12; Amos 1:13-15; Jer 49:1-6). The etiological function of the passage — explaining the origin of two historically significant neighbor-nations — is clear: the Moabites and Ammonites are Lot's descendants, which establishes their relationship to Israel (Semitic cousins, closer than Canaanites or Egyptians) while also marking their origin outside the covenant line.</p>"""
  }
}

def main():
    existing = load_comm('mkt-context', 'genesis')
    before_count = sum(len(v) for v in existing.values())
    merge_comm(existing, GENESIS_CONTEXT)
    save_comm('mkt-context', 'genesis', existing)

    result = load_comm('mkt-context', 'genesis')
    after_count = sum(len(v) for v in result.values())
    print(f'  Verses added: {after_count - before_count}')
    for ch in [17, 18, 19]:
        ck = str(ch)
        n = len(result.get(ck, {}))
        print(f'  Ch {ch}: {n} verses present')
    total_chs = len(result)
    total_vv = sum(len(v) for v in result.values())
    print(f'  Genesis context total: {total_chs} chapters, {total_vv} verses')
    print('Genesis 17–19 mkt-context written.')

if __name__ == '__main__':
    main()
